import Strum from './Strum';
import Cloudmine from './Cloudmine';
import Atlas from './Atlas';
import {Routes, Route, Link} from 'react-router-dom';
import React from 'react';
import { CarouselProvider, Slider, Slide, ButtonBack, ButtonNext } from 'pure-react-carousel';
import 'pure-react-carousel/dist/react-carousel.es.css';
function Projects() {
    return (
             
        <div>
            <h1 className="about">Projects</h1>
            <CarouselProvider
        naturalSlideWidth={100}
        naturalSlideHeight={125}
        totalSlides={3}
        visibleSlides={2}
        className="container">
            <Slider className="slider" >
            <div className="project-container">
            <Slide index={0} className="project-container-slider">
            <Link to="/projects/strum" className="project-container-text">
            <div>
            <h2 className="project-container-text" >01</h2>
            <Link to="/projects/strum" className="project-container-text-1">Strum</Link>
            <h1 className="project-text" >  Designing, creating and developing the web page for ceramic studio</h1>
            </div>
            </Link>
            </Slide>
            <Slide index={1} className="project-container-slider">
            <Link to="/projects/cloudmine" className="project-container-text">
            <div>
            <h2 className="project-container-text" >02</h2>
            <Link to="/projects/cloudmine" className="project-container-text">Cloudmine</Link>
            <h1 className="project-text" > Developing the web page for online shop</h1>
            </div>
            </Link>
            </Slide>
            <Slide index={2} className="project-container-slider">
            <Link to="/projects/atlas" className="project-container-text">
            <div>
            <h2 className="project-container-text" >03</h2>
            <Link to="/projects/atlas" className="project-container-text">Atlas</Link>
            <h1 className="project-text" > Designing and Prototyping</h1>
            </div>
            </Link>
            </Slide>
            </div>
            </Slider>
            <ButtonBack >Back</ButtonBack>
            <ButtonNext>Next</ButtonNext>
            </CarouselProvider>
            
        <Routes>
        <Route path="/projects/strum" element={<Strum/>}/>
        <Route path="/projects/cloudmine" element={<Cloudmine/>}/>
        <Route path="/projects/atlas" element={<Atlas/>}/>
        </Routes>
        </div>
    );
};

export default Projects;